import { useCallback, useEffect, useRef, useState } from "react";
import {
  isCrossOriginIsolated,
  createAudioEngine,
  type AudioEngineContext,
} from "@audio/index";
import { CrossOriginError, ClickToStart, DawShell } from "@ui/index";
import { useDawStore } from "@state/index";

export function App(): React.JSX.Element {
  const crossOriginOk = isCrossOriginIsolated();
  const [audioStarted, setAudioStarted] = useState(false);
  const engineRef = useRef<AudioEngineContext | null>(null);
  const setEngineStatus = useDawStore((s) => s.setEngineStatus);

  const handleStart = useCallback((): void => {
    if (engineRef.current) return;

    let engine: AudioEngineContext;
    try {
      engine = createAudioEngine();
    } catch {
      setEngineStatus("error");
      return;
    }

    engineRef.current = engine;
    engine.resume().then(
      () => {
        if (engineRef.current !== engine) return;
        setEngineStatus("running");
        setAudioStarted(true);
      },
      () => {
        void engine.close();
        if (engineRef.current === engine) {
          engineRef.current = null;
        }
        setEngineStatus("error");
      },
    );
  }, [setEngineStatus]);

  useEffect(() => {
    return () => {
      void engineRef.current?.close();
      engineRef.current = null;
    };
  }, []);

  if (!crossOriginOk) {
    return <CrossOriginError />;
  }

  if (!audioStarted) {
    return <ClickToStart onStart={handleStart} />;
  }

  return <DawShell />;
}

import { Toolbar } from "./Toolbar";
import { ArrangementPanel, MixerPanel, InstrumentPanel } from "./panels";

export function DawShell(): React.JSX.Element {
  return (
    <div
      data-testid="daw-shell"
      style={{
        display: "flex",
        flexDirection: "column",
        height: "100vh",
        backgroundColor: "var(--color-black)",
      }}
    >
      <Toolbar />
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          flex: 1,
          overflow: "hidden",
        }}
      >
        <ArrangementPanel />
        <MixerPanel />
        <InstrumentPanel />
      </div>
    </div>
  );
}

export function Toolbar(): React.JSX.Element {
  return (
    <header
      data-testid="toolbar"
      style={{
        height: "var(--space-12)",
        backgroundColor: "var(--color-gray-900)",
        borderBottom: "var(--border)",
        display: "flex",
        alignItems: "center",
        padding: "0 var(--space-4)",
        fontFamily: "var(--font-mono)",
        color: "var(--color-white)",
        fontSize: "var(--text-base)",
      }}
    >
      <span style={{ fontWeight: 700 }}>BRUTALWAV</span>
    </header>
  );
}

