1	export type ShortcutBinding = {
2	  key: string;
3	  ctrl?: boolean;
4	  shift?: boolean;
5	  alt?: boolean;
6	  meta?: boolean;
7	  commandId: string;
8	};
9	
10	function normalizeKey(key: string): string {
11	  return key === " " ? "space" : key.toLowerCase();
12	}
13	
14	export class ShortcutMap {
15	  private bindings: ShortcutBinding[] = [];
16	
17	  bind(binding: ShortcutBinding): void {
18	    this.bindings.push(binding);
19	  }
20	
21	  unbind(commandId: string): void {
22	    this.bindings = this.bindings.filter((b) => b.commandId !== commandId);
23	  }
24	
25	  resolve(event: KeyboardEvent): string | undefined {
26	    const eventKey = normalizeKey(event.key);
27	    const match = this.bindings.find(
28	      (b) =>
29	        normalizeKey(b.key) === eventKey &&
30	        (b.ctrl === true) === event.ctrlKey &&
31	        (b.shift === true) === event.shiftKey &&
32	        (b.alt === true) === event.altKey &&
33	        (b.meta === true) === event.metaKey,
34	    );
35	    return match?.commandId;
36	  }
37	
38	  getBindingsForCommand(commandId: string): ShortcutBinding[] {
39	    return this.bindings.filter((b) => b.commandId === commandId);
40	  }
41	
42	  getAll(): readonly ShortcutBinding[] {
43	    return [...this.bindings];
44	  }
45	}
46

1	import { useEffect } from "react";
2	import type { CommandRegistry } from "./command-registry";
3	import type { ShortcutMap } from "./shortcut-map";
4	
5	const IGNORED_TAGS = new Set(["INPUT", "TEXTAREA", "SELECT"]);
6	
7	export function useKeyboardShortcuts(
8	  registry: CommandRegistry,
9	  shortcuts: ShortcutMap,
10	): void {
11	  useEffect(() => {
12	    function handleKeyDown(event: KeyboardEvent): void {
13	      const target = event.target;
14	      if (target instanceof HTMLElement) {
15	        if (IGNORED_TAGS.has(target.tagName)) {
16	          return;
17	        }
18	        if (target.isContentEditable) {
19	          return;
20	        }
21	      }
22	
23	      const commandId = shortcuts.resolve(event);
24	      if (commandId === undefined) {
25	        return;
26	      }
27	
28	      const executed = registry.execute(commandId);
29	      if (executed) {
30	        event.preventDefault();
31	      }
32	    }
33	
34	    document.addEventListener("keydown", handleKeyDown);
35	    return (): void => {
36	      document.removeEventListener("keydown", handleKeyDown);
37	    };
38	  }, [registry, shortcuts]);
39	}
