  1	/**
  2	 * Transport state machine with cursor tracking.
  3	 * Writes cursor position, state, and BPM to SharedArrayBuffer
  4	 * for lock-free audio-thread <-> UI-thread communication.
  5	 */
  6	
  7	import { createTempoMap, type TempoMap } from "./tempo-map";
  8	import { TransportLayout } from "./shared-buffer-layout";
  9	
 10	export type TransportState = "stopped" | "playing" | "paused";
 11	
 12	const STATE_STOPPED = 0;
 13	const STATE_PLAYING = 1;
 14	const STATE_PAUSED = 2;
 15	
 16	export type TransportClock = {
 17	  readonly state: TransportState;
 18	  play(): void;
 19	  pause(): void;
 20	  stop(): void;
 21	  seek(seconds: number): void;
 22	  setBpm(bpm: number): void;
 23	  getCursorSeconds(): number;
 24	  getTempoMap(): TempoMap;
 25	  dispose(): void;
 26	};
 27	
 28	export function createTransportClock(
 29	  ctx: AudioContext,
 30	  transportSAB: SharedArrayBuffer,
 31	  initialBpm = 120,
 32	  sampleRate?: number,
 33	): TransportClock {
 34	  const rate = sampleRate ?? ctx.sampleRate;
 35	
 36	  // SAB views -- created once (zero-allocation convention INV-3)
 37	  const cursorView = new Float64Array(
 38	    transportSAB,
 39	    TransportLayout.CURSOR_SECONDS,
 40	    1,
 41	  );
 42	  const stateView = new Uint8Array(transportSAB, TransportLayout.STATE, 1);
 43	  const bpmView = new Float32Array(transportSAB, TransportLayout.BPM, 1);
 44	
 45	  let currentState: TransportState = "stopped";
 46	  let cursorSeconds = 0;
 47	  let playStartContextTime = 0;
 48	  let playStartCursorSeconds = 0;
 49	  let tempoMap = createTempoMap(
 50	    initialBpm,
 51	    { numerator: 4, denominator: 4 },
 52	    rate,
 53	  );
 54	
 55	  // Write initial values to SAB
 56	  stateView[0] = STATE_STOPPED;
 57	  bpmView[0] = initialBpm;
 58	  cursorView[0] = 0;
 59	
 60	  function writeSABState(state: number): void {
 61	    stateView[0] = state;
 62	  }
 63	
 64	  function writeSABCursor(seconds: number): void {
 65	    cursorView[0] = seconds;
 66	  }
 67	
 68	  const clock: TransportClock = {
 69	    get state(): TransportState {
 70	      return currentState;
 71	    },
 72	
 73	    play(): void {
 74	      if (currentState === "playing") return;
 75	
 76	      playStartContextTime = ctx.currentTime;
 77	      playStartCursorSeconds = cursorSeconds;
 78	      currentState = "playing";
 79	      writeSABState(STATE_PLAYING);
 80	    },
 81	
 82	    pause(): void {
 83	      if (currentState !== "playing") return;
 84	
 85	      cursorSeconds =
 86	        playStartCursorSeconds + (ctx.currentTime - playStartContextTime);
 87	      currentState = "paused";
 88	      writeSABState(STATE_PAUSED);
 89	      writeSABCursor(cursorSeconds);
 90	    },
 91	
 92	    stop(): void {
 93	      if (currentState === "stopped") return;
 94	
 95	      cursorSeconds = 0;
 96	      currentState = "stopped";
 97	      writeSABState(STATE_STOPPED);
 98	      writeSABCursor(0);
 99	    },
100	
101	    seek(seconds: number): void {
102	      cursorSeconds = seconds;
103	      if (currentState === "playing") {
104	        playStartContextTime = ctx.currentTime;
105	        playStartCursorSeconds = seconds;
106	      }
107	      writeSABCursor(seconds);
108	    },
109	
110	    setBpm(bpm: number): void {
111	      const clamped = Math.min(999, Math.max(20, bpm));
112	      tempoMap = createTempoMap(clamped, tempoMap.timeSignature, rate);
113	      bpmView[0] = clamped;
114	    },
115	
116	    getCursorSeconds(): number {
117	      if (currentState === "playing") {
118	        const elapsed = ctx.currentTime - playStartContextTime;
119	        const pos = playStartCursorSeconds + elapsed;
120	        writeSABCursor(pos);
121	        return pos;
122	      }
123	      return cursorSeconds;
124	    },
125	
126	    getTempoMap(): TempoMap {
127	      return tempoMap;
128	    },
129	
130	    dispose(): void {
131	      currentState = "stopped";
132	      writeSABState(STATE_STOPPED);
133	    },
134	  };
135	
136	  return clock;
137	}

